// v0.9：success 分支 — Extract success 不保留 fileName 在 json，改從 Read 用 fileName 反查
// 反查邏輯：input item 的 binary.data.fileName（如果有）→ fileName 反查 → 都不行就用 Extract success 的 i 直接對齊 Read 排除壞檔後的順序

const GEMINI_API_KEY = '__GEMINI_API_KEY__';
const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const items = $input.all();
const allReadItems = $('Read 所有 PDF').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  // 找對應 Read item：先用 binary.data.fileName，再用 i 對齊（Extract success 順序跟 Read 一致）
  let readItem = null;
  let binarySource = 'unknown';
  const binFileName = item.binary?.data?.fileName;
  if (binFileName) {
    readItem = allReadItems.find(r => r?.json?.fileName === binFileName);
    binarySource = 'binary-fileName';
  }
  if (!readItem) {
    readItem = allReadItems[i];
    binarySource = 'index-' + i;
  }

  const originalName = readItem?.json?.fileName || 'unknown.pdf';
  const binary = readItem?.binary;

  if (!binary || !binary.data) {
    throw new Error('[i=' + i + '] No binary. originalName=' + originalName + ', binFileName=' + binFileName + ', readNames=[' + allReadItems.map(r => r?.json?.fileName).join('|') + ']');
  }

  const pdfText = item.json.text || '';

  const prompt = '分析以下 PDF 文字，生成語意化檔名（不含 .pdf）。格式：YYYYMMDD_主題_關鍵字（繁體中文）。沒日期就用 ' + today + '。直接回檔名一行（不要 markdown）。\n\n<PDF>\n' + pdfText.substring(0, 2500) + '\n</PDF>';

  let aiResponse = '';
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
      headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
      body: {
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.3, maxOutputTokens: 200, thinkingConfig: { thinkingBudget: 0 } }
      },
      json: true,
      timeout: 30000
    });
    aiResponse = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  } catch (err) {}

  const trimmed = aiResponse.trim().replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
  let newFilename;
  if (trimmed && /^\d{8}[_\-]/.test(trimmed)) {
    newFilename = trimmed.split('\n')[0];
  } else {
    const m = aiResponse.match(/(\d{8}[_\-][^\s"',\n]+)/);
    if (m) { newFilename = m[1]; }
  }
  if (!newFilename) {
    newFilename = today + '_AI解析失敗_' + originalName.replace(/\.pdf$/i, '');
  }
  newFilename = newFilename.replace(/[\\/:*?"<>|]/g, '_').replace(/\.pdf$/i, '').substring(0, 100);

  results.push({
    json: {
      status: 'success',
      originalName,
      newFilename,
      newPath: '/files/shared/batch-inbox/processed/' + newFilename + '.pdf',
      binarySource
    },
    binary
  });
}

return results;

// v0.8：fail 分支 — fileName 對齊（不靠 pairedItem，n8n Extract error 分支會標錯到 0）
// Extract error 保留 fileName 在 json 但 strip binary，所以 fileName 從 input 拿，binary 用 fileName 從 Read 反查

const items = $input.all();
const allReadItems = $('Read 所有 PDF').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const originalName = item.json.fileName || 'unknown.pdf';

  // 用 fileName 反查（pairedItem 在 Extract error 分支不準）
  const readItem = allReadItems.find(r => r?.json?.fileName === originalName);
  const binary = readItem?.binary;
  const binarySource = readItem ? 'fileName-match' : 'NOT_FOUND';

  if (!binary || !binary.data) {
    throw new Error('[fail i=' + i + '] No binary for fileName=' + originalName + ', readNames=[' + allReadItems.map(r => r?.json?.fileName).join('|') + ']');
  }

  const errorMsg = item.json.error || JSON.stringify(item.json).substring(0, 500);

  results.push({
    json: {
      status: 'failed',
      originalName,
      errorMsg,
      failedPath: '/files/shared/batch-inbox/failed/' + originalName,
      binarySource
    },
    binary
  });
}

return results;
